async function initCreateRepo() {
    const name = prompt("Enter New Repository Name:");
    if (!name) return;
    const isPrivate = confirm("Make repository Private? (Cancel for Public)");

    toggleFabMenu();
    showGlobalToast("🚀 Provisioning Repository...");

    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'create_repo', name, is_private: isPrivate })
        });
        const data = await res.json();

        if (data.success) {
            showGlobalToast("✅ Repository Created!");
            // Auto-update local settings to point to new repo
            document.getElementById('setting-repo-name').value = data.repo_name;
            saveSettings();
            setTimeout(() => {
                switchTab('tab-context', document.querySelectorAll('.nav-item')[0]);
                fetchFileList();
            }, 1000);
        } else {
            throw new Error(data.error || "Failed to create repo");
        }
    } catch(e) {
        alert("Error: " + e.message);
    }
}

